import{_ as r}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o as n,c as l,a as e,b as t,d as a,f as s}from"./app-f83986bb.js";const c={},d=e("h1",{id:"web服务器",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#web服务器","aria-hidden":"true"},"#"),t(" web服务器")],-1),h=e("h2",{id:"tomcat",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#tomcat","aria-hidden":"true"},"#"),t(" tomcat")],-1),p={href:"https://www.likecs.com/show-305337039.html",target:"_blank",rel:"noopener noreferrer"},u={href:"https://mp.weixin.qq.com/s?__biz=MzA5ODA0NDE2MA==&mid=2649774376&idx=1&sn=5273159548ea223775dd3d14528e8f3a&chksm=88936947bfe4e0517c1d025d4f3fff754a5e4b907dba94a0189e4591d90dbd672d7c32a92896&scene=27",target:"_blank",rel:"noopener noreferrer"},b=s('<ul><li>web服务器，实现了对 Java Servlet 和 JSP（JavaServer Pages）技术的支持</li><li>前身是catalina servlet 容器，用于运行servlet程序</li></ul><h3 id="applicationcontext与standardcontext" tabindex="-1"><a class="header-anchor" href="#applicationcontext与standardcontext" aria-hidden="true">#</a> ApplicationContext与StandardContext</h3><ul><li>职责不同</li><li>StandardContext掌握控制权，也是一个容器，负责servlet的选择，session cookie 的管理</li><li>ApplicationContext是servlet运行环境的上下文信息</li></ul><h3 id="standardcontext" tabindex="-1"><a class="header-anchor" href="#standardcontext" aria-hidden="true">#</a> StandardContext</h3><p>负责servlet的选择，session cookie 的管理</p><ul><li>getServletContext 获取ServletContext</li></ul><h3 id="applicationcontext" tabindex="-1"><a class="header-anchor" href="#applicationcontext" aria-hidden="true">#</a> ApplicationContext</h3><h3 id="从组件角度" tabindex="-1"><a class="header-anchor" href="#从组件角度" aria-hidden="true">#</a> 从组件角度</h3><blockquote><p>server</p></blockquote><p>服务器顶层，可以包含多个service</p><blockquote><p>service</p></blockquote><ul><li>一个service只有一个engine</li><li>可以有多个connector处理不同协议的请求</li></ul><blockquote><p>connector</p></blockquote><ol><li>支持多种协议</li><li>连接容器和service</li><li>封装request和response</li><li>对请求的封装使用了包装器RequestFacade</li><li>交给servlet后还会对请求包装ServletRequestWrapper、HttpServletRequestWrapper</li></ol><blockquote><p>container 引擎(Engine)、主机(Host)、上下文(Context)和Wraper均继承自Container接口，所以它们都是容器。</p></blockquote><ul><li>engine 可配置多个host，一个ip对应多个域名，以域名划分host容器</li><li>host host可配置多个context，有默认host,即webapps目录</li><li>context 这里的上下文即standardContext(standardContext实现context接口)属于host,即一个web应用，默认root文件夹，可配置其他文件夹</li><li>wrapper 封装着一个servlet</li></ul><blockquote><p>service内部组件</p></blockquote><ul><li>Manager servletContext中的组件，管理session会话</li><li>logger 日志</li><li>context 加载器，和类加载有关，只会开放给Context所使用</li><li>pipeline 管道组件，配合Valve实现过滤器功能</li><li>value 阀门组件，配合Pipeline实现过滤器功能</li></ul><h3 id="从一个完整请求的角度来看" tabindex="-1"><a class="header-anchor" href="#从一个完整请求的角度来看" aria-hidden="true">#</a> 从一个完整请求的角度来看</h3><p>假设来自客户的请求为：http://localhost:8080/test/index.jsp 请求被发送到本机端口8080，被在那里侦听的Coyote HTTP/1.1 Connector,然后</p><ul><li>Connector把该请求交给它所在的Service的Engine来处理，并等待Engine的回应</li><li>Engine获得请求localhost:8080/test/index.jsp，匹配它所有虚拟主机Host</li><li>Engine匹配到名为localhost的Host(即使匹配不到也把请求交给该Host处理，因为该Host被定义为该Engine的默认主机) localhost</li><li>Host获得请求/test/index.jsp，匹配它所拥有的所有Context</li><li>Host匹配到路径为/test的Context(如果匹配不到就把该请求交给路径名为&quot;&quot;的Context去处理)</li><li>path=&quot;/test&quot;的Context获得请求/index.jsp，在它的mapping table中寻找对应的servlet</li><li>Context匹配到URL PATTERN为*.jsp的servlet，对应于JspServlet类，构造HttpServletRequest对象和HttpServletResponse对象，作为参数调用JspServlet的doGet或doPost方法</li><li>Context把执行完了之后的HttpServletResponse对象返回给Host</li><li>Host把HttpServletResponse对象返回给Engine</li><li>Engine把HttpServletResponse对象返回给Connector</li><li>Connector把HttpServletResponse对象返回给客户browse</li></ul><h3 id="从后续深入理解的角度" tabindex="-1"><a class="header-anchor" href="#从后续深入理解的角度" aria-hidden="true">#</a> 从后续深入理解的角度</h3><ul><li>基于组件的架构</li><li>基于生命周期<br> 各个组件的源代码，会发现绝大多数组件实现了Lifecycle接口，这也就是我们所说的基于生命周期。生命周期的各个阶段的触发又是基于事件的方式。</li><li>基于JMX</li></ul><h3 id="servlet引擎-容器" tabindex="-1"><a class="header-anchor" href="#servlet引擎-容器" aria-hidden="true">#</a> servlet引擎(容器)</h3><p>Servlet没有main方法，所以，如果要执行，则需要在一个容器里面才能执行，这个容器就是为了支持Servlet的功能而存在</p><h3 id="jsp引擎" tabindex="-1"><a class="header-anchor" href="#jsp引擎" aria-hidden="true">#</a> jsp引擎</h3><p>将jsp转为servlet，代码动态构建网页输出</p><h3 id="线程模型" tabindex="-1"><a class="header-anchor" href="#线程模型" aria-hidden="true">#</a> 线程模型</h3><ul><li>acceptor</li><li>poller</li><li>worker线程池</li></ul><h3 id="org-apache-coyote-response" tabindex="-1"><a class="header-anchor" href="#org-apache-coyote-response" aria-hidden="true">#</a> org.apache.coyote.Response</h3><h3 id="nioendpoint-nio2endpoint-abstractendpoint" tabindex="-1"><a class="header-anchor" href="#nioendpoint-nio2endpoint-abstractendpoint" aria-hidden="true">#</a> NioEndpoint,Nio2Endpoint,AbstractEndpoint</h3><ul><li>createSocketProcessor</li><li>processSocket 创建线程任务SocketProcessor交给线程池执行</li></ul><h3 id="nioacceptor-nioendpoint下的accept任务" tabindex="-1"><a class="header-anchor" href="#nioacceptor-nioendpoint下的accept任务" aria-hidden="true">#</a> NioAcceptor，NioEndpoint下的accept任务</h3><ul><li>run</li></ul><h3 id="socketprocessor-nioendpoint下的内部类" tabindex="-1"><a class="header-anchor" href="#socketprocessor-nioendpoint下的内部类" aria-hidden="true">#</a> SocketProcessor，NioEndpoint下的内部类</h3><ul><li>doRun</li></ul><h3 id="connector" tabindex="-1"><a class="header-anchor" href="#connector" aria-hidden="true">#</a> Connector</h3><ul><li>实例时创建ProtocolHandler的实现Http11NioProtocol</li><li>initInternal，初始化CoyoteAdapter，并塞到ProtocolHandler中</li></ul><h3 id="http11nioprotocol-http11nio2protocol-abstracthttp11jsseprotocol-abstracthttp11protocol-abstractprotocol" tabindex="-1"><a class="header-anchor" href="#http11nioprotocol-http11nio2protocol-abstracthttp11jsseprotocol-abstracthttp11protocol-abstractprotocol" aria-hidden="true">#</a> Http11NioProtocol,Http11Nio2Protocol,AbstractHttp11JsseProtocol,AbstractHttp11Protocol,AbstractProtocol</h3><p>实例化Http11NioProtocol，同时创建NioEndpoint，ConnectionHandler</p><h4 id="connectionhandler-abstractprotocol下的内部类" tabindex="-1"><a class="header-anchor" href="#connectionhandler-abstractprotocol下的内部类" aria-hidden="true">#</a> ConnectionHandler，AbstractProtocol下的内部类</h4><ul><li>process 创建Http11Processor处理socketWrapper,socket</li></ul><h3 id="http11processor-abstractprocessorlight-processor" tabindex="-1"><a class="header-anchor" href="#http11processor-abstractprocessorlight-processor" aria-hidden="true">#</a> Http11Processor,AbstractProcessorLight,Processor</h3><ul><li>process</li><li>service</li><li>action</li></ul><h3 id="coyoteadapter" tabindex="-1"><a class="header-anchor" href="#coyoteadapter" aria-hidden="true">#</a> CoyoteAdapter</h3><p>创建ServletRequest,ServletResponse,并设置 org.apache.coyote.Request req, org.apache.coyote.Response res,主要用于数据的交互</p><h3 id="lifecyclebase" tabindex="-1"><a class="header-anchor" href="#lifecyclebase" aria-hidden="true">#</a> LifecycleBase</h3><ul><li>StandardServer, 包含service</li><li>StandardService,包含connector</li></ul><h3 id="container" tabindex="-1"><a class="header-anchor" href="#container" aria-hidden="true">#</a> Container</h3><ul><li>StandardEngine</li><li>StandardHost</li><li>StandardContext</li><li>StandardWrapper <ul><li>ApplicationDispatcher</li></ul></li><li>pipeline <ul><li>base</li></ul></li></ul><h3 id="servlet3-0-异步请求" tabindex="-1"><a class="header-anchor" href="#servlet3-0-异步请求" aria-hidden="true">#</a> servlet3.0 异步请求</h3><ul><li>HttpServletRequest的startAsync启动异步处理，释放容器worker线程</li><li>AsyncContextImpl,AsyncContext <ul><li>setStarted</li><li>AsyncRunnable 设置请求状态为DISPATCHED</li></ul></li></ul><h4 id="asyncstatemachine" tabindex="-1"><a class="header-anchor" href="#asyncstatemachine" aria-hidden="true">#</a> AsyncStateMachine</h4><ul><li>DISPATCHED 非异步状态</li><li>STARTING</li><li>STARTED</li><li>DISPATCHING</li></ul><h2 id="jetty" tabindex="-1"><a class="header-anchor" href="#jetty" aria-hidden="true">#</a> jetty</h2><h2 id="undertow" tabindex="-1"><a class="header-anchor" href="#undertow" aria-hidden="true">#</a> undertow</h2>',56);function x(v,f){const o=i("ExternalLinkIcon");return n(),l("div",null,[d,h,e("p",null,[e("a",p,[t("参考"),a(o)])]),e("p",null,[e("a",u,[t("参考"),a(o)])]),b])}const H=r(c,[["render",x],["__file","web服务器.html.vue"]]);export{H as default};
